1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const countLiveNeighbors = ([x, y]: Cell, alive: ReadonlySet<string>): number =>
12	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => alive.has(cellKey([x + dx, y + dy]))).length;
13	
14	const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const alive = new Set(cells.map(cellKey));
18	  return cells.filter((cell) => survives(countLiveNeighbors(cell, alive)));
19	}
