1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep alive a cell with 2 live neighbors (survival)", () => {
15	    // Horizontal blinker: center cell (1,0) has 2 neighbors → survives
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("should keep alive a cell with 3 live neighbors (survival)", () => {
20	    // 2x2 block: each cell has 3 neighbors → all survive (still life)
21	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
22	    expect(result).toContainEqual([0, 0]);
23	    expect(result).toContainEqual([1, 0]);
24	    expect(result).toContainEqual([0, 1]);
25	    expect(result).toContainEqual([1, 1]);
26	  });
27	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
28	    // Plus shape: center (1,1) has 4 neighbors → dies
29	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]]);
30	    expect(result).not.toContainEqual([1, 1]);
31	  });
32	  it.todo("should bring a dead cell with exactly 3 neighbors to life (reproduction)");
33	  it.todo("should oscillate a blinker pattern correctly");
34	  it.todo("should handle negative coordinates correctly");
35	});
